'use client'
import {useCallback, useEffect, useMemo, useState} from 'react'
import {
  Activity, Bell, Building2, CheckCircle2, Copy, CreditCard, Gift, Loader2,
  MapPin, Pencil, Plus, RefreshCw, Save, Send, ShieldCheck, Sparkles, Stamp,
  Upload, UserCog, Users, WalletCards, XCircle
} from 'lucide-react'
import {api, API} from '@/lib/api'
import {Shell} from '@/components/Shell'

type Row = Record<string, any>
type Me = {id:string;name:string;email:string;role:string;brands:{id:string;name:string;slug:string;role:string;permissions?:Record<string,boolean>}[]}
const emptyDesign={background_color:'#111827',foreground_color:'#FFFFFF',label_color:'#C6FF4A',logo_text:'LOYALYN',card_title:'بطاقة الولاء',logo_url:'',hero_url:'',barcode_format:'PKBarcodeFormatQR',terms:'',fields:{show_points:true,show_stamps:true,show_rewards:true,show_tier:true,show_visits:true}}
const emptyProgram={enabled:true,program_type:'hybrid',points_per_visit:10,points_per_currency:1,required_stamps:6,stamp_reward_title:'مكافأة مجانية',reward_points:100,reward_title:'مكافأة مجانية',birthday_bonus:0,referral_bonus:0,cashback_percent:0,points_expiry_days:null,daily_points_cap:null,allow_manual_adjustment:true,rules:{auto_convert_points:false,global_multiplier:1,weekday_multipliers:{},branch_multipliers:{},happy_hours:[]}}

export default function AdminPage(){
  const [me,setMe]=useState<Me|null>(null)
  const [brands,setBrands]=useState<Row[]>([])
  const [brand,setBrand]=useState('')
  const [tab,setTab]=useState('overview')
  const [data,setData]=useState<Record<string,any>>({})
  const [loading,setLoading]=useState(true)
  const [busy,setBusy]=useState('')
  const [toast,setToast]=useState<{type:'ok'|'error';text:string}|null>(null)
  const selected=useMemo(()=>brands.find(x=>x.id===brand),[brands,brand])
  const selectedAccess=useMemo(()=>me?.brands?.find(x=>x.id===brand),[me,brand])

  const tell=(text:string,type:'ok'|'error'='ok')=>{setToast({text,type});setTimeout(()=>setToast(null),4500)}
  const run=async(key:string,fn:()=>Promise<any>,success?:string)=>{setBusy(key);try{const result=await fn();if(success)tell(success);return result}catch(e:any){tell(e.message||'حدث خطأ غير متوقع','error');throw e}finally{setBusy('')}}

  const loadCore=useCallback(async()=>{
    setLoading(true)
    try{
      const profile=await api<Me>('/api/auth/me')
      const brandRows=await api<Row[]>('/api/brands')
      setMe(profile);setBrands(brandRows)
      const stored=localStorage.getItem('loyalyn_brand')
      const first=brandRows.find(x=>x.id===stored)?.id||brandRows[0]?.id||''
      setBrand(first)
    }catch(e:any){tell(e.message,'error')}finally{setLoading(false)}
  },[tab])

  const loadTab=useCallback(async()=>{
    if(!me)return
    if(!brand&&tab!=='brands'&&tab!=='platform-wallet'){setData({});return}
    setLoading(true)
    try{
      let payload:any={}
      if(tab==='overview')payload=await api(`/api/dashboard${brand?`?brand_id=${brand}`:''}`)
      if(tab==='branches')payload={branches:await api(`/api/management/branches?brand_id=${brand}`)}
      if(tab==='customers'){const [customers,rewards,coupons,branches]=await Promise.all([api(`/api/customers?brand_id=${brand}&active_only=false`),api(`/api/management/rewards?brand_id=${brand}`),api(`/api/management/coupons?brand_id=${brand}`),api(`/api/management/branches?brand_id=${brand}`)]);payload={customers,rewards,coupons,branches}}
      if(tab==='staff')payload={staff:await api(`/api/management/staff?brand_id=${brand}`),branches:await api(`/api/management/branches?brand_id=${brand}`)}
      if(tab==='loyalty'){
        const [program,tiers,rewards,coupons,branches]=await Promise.all([api(`/api/customers/program/${brand}`),api(`/api/management/tiers?brand_id=${brand}`),api(`/api/management/rewards?brand_id=${brand}`),api(`/api/management/coupons?brand_id=${brand}`),api(`/api/management/branches?brand_id=${brand}`)])
        payload={program,tiers,rewards,coupons,branches}
      }
      if(tab==='wallet')payload={design:await api(`/api/wallet/design/${brand}`),customers:await api(`/api/customers?brand_id=${brand}`)}
      if(tab==='campaigns'){const [campaigns,templates,customers,branches]=await Promise.all([api(`/api/notifications/campaigns?brand_id=${brand}`),api(`/api/notifications/templates?brand_id=${brand}`),api(`/api/customers?brand_id=${brand}&active_only=false`),api(`/api/management/branches?brand_id=${brand}`)]);payload={campaigns,templates,customers,branches}}
      if(tab==='audit')payload={audit:await api(`/api/management/audit?brand_id=${brand}`)}
      if(tab==='platform-wallet')payload={credential:await api('/api/wallet/platform/credential')}
      setData(payload)
    }catch(e:any){tell(e.message,'error')}finally{setLoading(false)}
  },[tab,brand,me])

  useEffect(()=>{loadCore()},[])
  useEffect(()=>{if(me)loadTab()},[me,tab,brand,loadTab])
  useEffect(()=>{if(brand)localStorage.setItem('loyalyn_brand',brand)},[brand])

  async function submitJson(path:string,e:React.FormEvent<HTMLFormElement>,extra:Row={},method='POST',success='تم الحفظ بنجاح'){
    e.preventDefault();const form=e.currentTarget;const fd=new FormData(form);const body:Row={...extra}
    fd.forEach((value,key)=>{if(value==='')body[key]=null;else if(value==='on')body[key]=true;else body[key]=value})
    await run(path,()=>api(path,{method,body:JSON.stringify(body)}),success);form.reset();await loadTab()
  }

  async function createBrand(e:React.FormEvent<HTMLFormElement>){
    e.preventDefault();const form=e.currentTarget;const fd=new FormData(form)
    const body={name:fd.get('name'),slug:String(fd.get('slug')||'').toLowerCase().trim(),primary_color:fd.get('primary_color'),accent_color:fd.get('accent_color'),currency:fd.get('currency'),timezone:'Asia/Qatar',locale:'ar',manager_name:fd.get('manager_name')||null,manager_email:fd.get('manager_email')||null,manager_password:fd.get('manager_password')||null}
    const result=await run('brand-create',()=>api('/api/brands',{method:'POST',body:JSON.stringify(body)}))
    if(result?.manager?.temporary_password)tell(`تم إنشاء البراند. كلمة المرور المؤقتة للمدير: ${result.manager.temporary_password}`)
    else tell('تم إنشاء البراند وربط مديره')
    form.reset();await loadCore();if(result?.brand?.id)setBrand(result.brand.id)
  }

  async function loyaltyAction(customer:Row,action:'visit'|'spend'|'manual'){
    let amount=0,points=0,stamps=0,note=''
    if(action==='spend'){const value=prompt('أدخل قيمة الفاتورة');if(value===null)return;amount=Number(value);if(!Number.isFinite(amount)||amount<0)return tell('قيمة الفاتورة غير صحيحة','error')}
    if(action==='manual'){const p=prompt('عدد النقاط (يمكن استخدام رقم سالب للخصم)','0');if(p===null)return;const s=prompt('عدد الأختام (يمكن استخدام رقم سالب للخصم)','0');if(s===null)return;points=Number(p);stamps=Number(s);note=prompt('سبب التعديل')||''}
    await run(`loyalty-${customer.id}`,()=>api(`/api/customers/${customer.id}/loyalty`,{method:'POST',body:JSON.stringify({action,amount,points,stamps,note,idempotency_key:crypto.randomUUID()})}),'تم تحديث رصيد العميل')
    await loadTab()
  }

  async function issuePass(customer:Row){
    const result=await run(`pass-${customer.id}`,()=>api(`/api/wallet/passes/${customer.id}`,{method:'POST'}),'تم إصدار بطاقة Apple Wallet')
    if(result?.download_url){await navigator.clipboard.writeText(result.download_url);tell('تم إصدار البطاقة ونسخ رابط الإضافة')}
  }

  if(!me)return <main className="min-h-screen grid place-items-center"><Loader2 className="animate-spin"/></main>
  return <Shell active={tab} onChange={setTab} role={me.role} accessRole={selectedAccess?.role} userName={me.name} brandName={selected?.name}>
    <div className="max-w-[1500px] mx-auto">
      <Topbar title={tab==='brands'&&me.role!=='platform_owner'?'إعدادات البراند':titles[tab]||'لوحة التحكم'} subtitle={tab==='brands'&&me.role!=='platform_owner'?'تعديل هوية وإعدادات البراندات المصرح لك بها فقط.':subtitles[tab]||''} brands={brands} brand={brand} setBrand={setBrand} showBrand={tab!=='brands'&&tab!=='platform-wallet'} reload={loadTab}/>
      {toast&&<Toast {...toast} onClose={()=>setToast(null)}/>} 
      {tab==='overview'&&<Overview data={data} setTab={setTab}/>} 
      {tab==='brands'&&(me.role==='platform_owner'?<Brands brands={brands} onSubmit={createBrand} busy={busy} reload={loadCore} run={run}/>:<BrandSettings brand={selected} busy={busy} run={run} reload={loadCore}/>)} 
      {tab==='branches'&&<Branches rows={data.branches||[]} brand={brand} submit={submitJson} busy={busy} run={run} reload={loadTab}/>} 
      {tab==='customers'&&<Customers rows={data.customers||[]} rewards={data.rewards||[]} coupons={data.coupons||[]} branches={data.branches||[]} brand={brand} submit={submitJson} busy={busy} loyaltyAction={loyaltyAction} issuePass={issuePass} run={run} reload={loadTab}/>} 
      {tab==='staff'&&<Staff rows={data.staff||[]} branches={data.branches||[]} brand={brand} submit={submitJson} busy={busy} run={run} reload={loadTab}/>} 
      {tab==='loyalty'&&<Loyalty program={data.program||emptyProgram} tiers={data.tiers||[]} rewards={data.rewards||[]} coupons={data.coupons||[]} branches={data.branches||[]} brand={brand} busy={busy} run={run} reload={loadTab} submit={submitJson}/>} 
      {tab==='wallet'&&<WalletStudio design={data.design||emptyDesign} customers={data.customers||[]} brand={brand} brandInfo={selected} busy={busy} run={run} reload={loadTab} issuePass={issuePass}/>} 
      {tab==='campaigns'&&<Campaigns rows={data.campaigns||[]} templates={data.templates||[]} customers={data.customers||[]} branches={data.branches||[]} brand={brand} busy={busy} run={run} reload={loadTab}/>} 
      {tab==='audit'&&<Audit rows={data.audit||[]}/>} 
      {tab==='platform-wallet'&&me.role==='platform_owner'&&<PlatformWallet credential={data.credential} busy={busy} run={run} reload={loadTab}/>} 
      {loading&&<div className="loading-layer"><Loader2 className="animate-spin"/><span>جاري تحديث البيانات...</span></div>}
    </div>
  </Shell>
}

const titles:Row={overview:'مركز التحكم',brands:'إدارة البراندات',branches:'الفروع',customers:'العملاء',staff:'الموظفون والصلاحيات',loyalty:'محرك الولاء',wallet:'استوديو Apple Wallet',campaigns:'الإشعارات والحملات',audit:'سجل التدقيق','platform-wallet':'شهادة Apple Wallet المركزية'}
const subtitles:Row={overview:'متابعة المنصة والعمليات من مكان واحد.',brands:'أنشئ البراند واربط مديره مباشرة.',branches:'إدارة الفروع وبياناتها التشغيلية.',customers:'تسجيل العملاء وتحديث الولاء وإصدار البطاقات.',staff:'حساب مستقل لكل مدير أو موظف وصلاحيات معزولة.',loyalty:'قواعد النقاط والأختام والمستويات والمكافآت.',wallet:'مدير البراند يصمم؛ مدير المنصة يحتفظ بالشهادة.',campaigns:'حملات فورية أو مجدولة مع حالة إرسال حقيقية.',audit:'كل تعديل مهم محفوظ وقابل للمراجعة.','platform-wallet':'لا يظهر هذا القسم إلا لمدير المنصة.'}

function Topbar({title,subtitle,brands,brand,setBrand,showBrand,reload}:any){return <header className="topbar"><div><p className="eyebrow">LOYALYN CONTROL CENTER · V3</p><h1>{title}</h1><p className="muted mt-2">{subtitle}</p></div><div className="top-actions">{showBrand&&<select className="input brand-select" value={brand} onChange={e=>setBrand(e.target.value)}>{brands.map((x:Row)=><option key={x.id} value={x.id}>{x.name}</option>)}</select>}<button className="icon-btn" onClick={reload} title="تحديث"><RefreshCw size={18}/></button></div></header>}
function Toast({type,text,onClose}:any){return <div className={`toast ${type}`}><span>{type==='ok'?<CheckCircle2/>:<XCircle/>}</span><b>{text}</b><button onClick={onClose}>×</button></div>}
function Panel({title,desc,action,children,className=''}:any){return <section className={`panel ${className}`}><div className="panel-head"><div><h2>{title}</h2>{desc&&<p>{desc}</p>}</div>{action}</div><div className="panel-body">{children}</div></section>}
function Empty({text='لا توجد بيانات بعد'}:{text?:string}){return <div className="empty-state"><Sparkles/><p>{text}</p></div>}
function Btn({busy,label,icon:Icon=Save,variant='primary',...props}:any){return <button {...props} disabled={busy||props.disabled} className={`btn ${variant}`}>{busy?<Loader2 size={17} className="animate-spin"/>:<Icon size={17}/>}<span>{label}</span></button>}
function Field({label,name,type='text',defaultValue,required=true,placeholder,children,...props}:any){return <label className="field"><span>{label}</span>{children||<input className="input" name={name} type={type} defaultValue={defaultValue} required={required} placeholder={placeholder} {...props}/>}</label>}
function Switch({label,name,defaultChecked}:any){return <label className="switch-row"><input type="checkbox" name={name} defaultChecked={defaultChecked}/><span>{label}</span></label>}
function Modal({title,desc,onClose,children}:any){return <div className="modal-backdrop" onMouseDown={e=>{if(e.target===e.currentTarget)onClose()}}><section className="modal-card"><div className="modal-head"><div><h2>{title}</h2>{desc&&<p>{desc}</p>}</div><button className="icon-btn" onClick={onClose} aria-label="إغلاق"><XCircle size={19}/></button></div><div className="modal-body">{children}</div></section></div>}

function Overview({data,setTab}:any){const cards=[[data.customers||0,'العملاء',Users],[data.new_customers_30d||0,'جدد خلال 30 يوم',Sparkles],[data.transactions||0,'عمليات الولاء',Activity],[data.wallet_passes||0,'بطاقات Wallet',WalletCards],[data.points_issued||0,'نقاط صادرة',Gift],[data.campaigns||0,'الحملات',Bell],[data.branches||0,'الفروع',MapPin],[data.staff||0,'الموظفون',UserCog]];return <><div className="kpi-grid">{cards.map(([value,label,Icon]:any)=><div className="kpi-card" key={label}><div className="kpi-icon"><Icon/></div><div><strong>{Number(value).toLocaleString('ar')}</strong><span>{label}</span></div></div>)}</div><div className="content-grid mt-5"><Panel title="إجراءات سريعة" desc="اختصارات للعمليات الأكثر استخدامًا"><div className="quick-grid">{[['customers','تسجيل عميل',Users],['loyalty','ضبط برنامج الولاء',Gift],['wallet','تصميم البطاقة',WalletCards],['campaigns','إنشاء حملة',Bell]].map(([id,label,Icon]:any)=><button className="quick-card" key={id} onClick={()=>setTab(id)}><Icon/><b>{label}</b><span>فتح القسم</span></button>)}</div></Panel><Panel title="آخر عمليات الولاء" desc="آخر التغييرات المسجلة في دفتر العمليات">{data.recent_activity?.length?<div className="activity-list">{data.recent_activity.map((x:Row)=><div key={x.id}><span className="dot-live"/><div><b>{actionName(x.action)}</b><small>{new Date(x.created_at).toLocaleString('ar-QA')}</small></div><em>{x.delta_points>=0?'+':''}{x.delta_points} نقطة · {x.delta_stamps>=0?'+':''}{x.delta_stamps} ختم</em></div>)}</div>:<Empty/>}</Panel></div></>}

function Brands({brands,onSubmit,busy,reload,run}:any){
  const [editing,setEditing]=useState<Row|null>(null)
  async function toggle(x:Row){await run(`brand-${x.id}`,()=>api(`/api/brands/${x.id}`,{method:'PATCH',body:JSON.stringify({is_active:!x.is_active})}),x.is_active?'تم إيقاف البراند':'تم تفعيل البراند');await reload()}
  async function update(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!editing)return;const fd=new FormData(e.currentTarget);await run(`edit-brand-${editing.id}`,()=>api(`/api/brands/${editing.id}`,{method:'PATCH',body:JSON.stringify({name:fd.get('name'),primary_color:fd.get('primary_color'),accent_color:fd.get('accent_color'),currency:fd.get('currency'),timezone:fd.get('timezone'),locale:fd.get('locale')})}),'تم تحديث البراند');setEditing(null);await reload()}
  return <div className="content-grid mt-6">
    <Panel title="إنشاء براند ومديره" desc="ينشأ البراند وإعدادات الولاء والتصميم الافتراضي وحساب المدير في عملية واحدة"><form className="form-grid" onSubmit={onSubmit}><Field label="اسم البراند" name="name"/><Field label="الرابط المختصر" name="slug" placeholder="coffee-house" pattern="[a-z0-9-]+"/><div className="two-col"><Field label="اللون الأساسي" name="primary_color" type="color" defaultValue="#111827"/><Field label="اللون المميز" name="accent_color" type="color" defaultValue="#C6FF4A"/></div><Field label="العملة" name="currency" defaultValue="QAR"/><div className="form-divider">حساب مدير البراند</div><Field label="اسم المدير" name="manager_name" required={false}/><Field label="بريد المدير" name="manager_email" type="email" required={false}/><Field label="كلمة مرور المدير" name="manager_password" type="password" required={false} minLength={8}/><Btn busy={busy==='brand-create'} label="إنشاء وربط البراند" icon={Plus}/></form></Panel>
    <Panel title="كل البراندات" desc={`${brands.length} براند داخل المنصة`}>{brands.length?<div className="card-list">{brands.map((x:Row)=><div className="entity-card" key={x.id}><div className="brand-mark" style={{background:x.primary_color,color:x.accent_color}}>{x.name[0]}</div><div className="entity-main"><b>{x.name}</b><small>{x.slug} · {x.currency} · {x.timezone}</small></div><span className={`badge ${x.is_active?'success':'muted-badge'}`}>{x.is_active?'فعال':'موقوف'}</span><div className="button-row"><Btn label="تعديل" icon={Pencil} variant="secondary" onClick={()=>setEditing(x)}/><Btn busy={busy===`brand-${x.id}`} label={x.is_active?'إيقاف':'تفعيل'} icon={x.is_active?XCircle:CheckCircle2} variant="secondary" onClick={()=>toggle(x)}/></div></div>)}</div>:<Empty/>}</Panel>
    {editing&&<Modal title="تعديل البراند" desc="يتم حفظ التعديل مباشرة في قاعدة البيانات" onClose={()=>setEditing(null)}><form className="form-grid" onSubmit={update}><Field label="اسم البراند" name="name" defaultValue={editing.name}/><div className="two-col"><Field label="اللون الأساسي" name="primary_color" type="color" defaultValue={editing.primary_color}/><Field label="اللون المميز" name="accent_color" type="color" defaultValue={editing.accent_color}/></div><Field label="العملة" name="currency" defaultValue={editing.currency}/><Field label="المنطقة الزمنية" name="timezone" defaultValue={editing.timezone||'Asia/Qatar'}/><Field label="اللغة" name="locale" defaultValue={editing.locale||'ar'}/><div className="button-row"><Btn busy={busy===`edit-brand-${editing.id}`} label="حفظ التعديلات"/><Btn type="button" label="إلغاء" variant="secondary" onClick={()=>setEditing(null)}/></div></form></Modal>}
  </div>
}

function BrandSettings({brand,busy,run,reload}:any){
  async function save(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!brand)return;const fd=new FormData(e.currentTarget);await run(`brand-settings-${brand.id}`,()=>api(`/api/brands/${brand.id}`,{method:'PATCH',body:JSON.stringify({name:fd.get('name'),primary_color:fd.get('primary_color'),accent_color:fd.get('accent_color'),currency:fd.get('currency'),timezone:fd.get('timezone'),locale:fd.get('locale')})}),'تم حفظ إعدادات البراند');await reload()}
  if(!brand)return <Panel title="إعدادات البراند" className="mt-6"><Empty text="اختر براندًا أولًا"/></Panel>
  return <div className="content-grid mt-6"><Panel title="هوية وإعدادات البراند" desc="هذه التغييرات تخص البراند المحدد فقط"><form className="form-grid" onSubmit={save}><Field label="اسم البراند" name="name" defaultValue={brand.name}/><div className="two-col"><Field label="اللون الأساسي" name="primary_color" type="color" defaultValue={brand.primary_color}/><Field label="اللون المميز" name="accent_color" type="color" defaultValue={brand.accent_color}/></div><Field label="العملة" name="currency" defaultValue={brand.currency}/><Field label="المنطقة الزمنية" name="timezone" defaultValue={brand.timezone||'Asia/Qatar'}/><Field label="اللغة" name="locale" defaultValue={brand.locale||'ar'}/><Btn busy={busy===`brand-settings-${brand.id}`} label="حفظ إعدادات البراند"/></form></Panel><Panel title="العزل والصلاحيات"><div className="rule-summary"><Rule icon={ShieldCheck} title="بيانات معزولة" text="كل عميل وموظف وعملية مرتبطة بهذا البراند"/><Rule icon={UserCog} title="مديرو البراند" text="يرون البراندات المصرح لهم بها فقط"/><Rule icon={WalletCards} title="Wallet مركزي" text="تصمم البطاقة دون الوصول إلى شهادة Apple"/><Rule icon={Bell} title="حملات مستقلة" text="الجمهور والسجل خاصان بهذا البراند"/></div></Panel></div>
}

function Branches({rows,brand,submit,busy,run,reload}:any){
  const [editing,setEditing]=useState<Row|null>(null)
  async function toggle(x:Row){await run(`branch-${x.id}`,()=>api(`/api/management/branches/${x.id}`,{method:'PATCH',body:JSON.stringify({is_active:!x.is_active})}),x.is_active?'تم إيقاف الفرع':'تم تفعيل الفرع');await reload()}
  async function update(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!editing)return;const fd=new FormData(e.currentTarget);await run(`edit-branch-${editing.id}`,()=>api(`/api/management/branches/${editing.id}`,{method:'PATCH',body:JSON.stringify({name:fd.get('name'),phone:fd.get('phone')||null,manager_name:fd.get('manager_name')||null,address:fd.get('address')||null,latitude:fd.get('latitude')||null,longitude:fd.get('longitude')||null})}),'تم تحديث الفرع');setEditing(null);await reload()}
  return <div className="content-grid mt-6"><Panel title="إضافة فرع"><form className="form-grid" onSubmit={(e)=>submit('/api/management/branches',e,{brand_id:brand},'POST','تم إنشاء الفرع')}><Field label="اسم الفرع" name="name"/><Field label="الهاتف" name="phone" required={false}/><Field label="مدير الفرع" name="manager_name" required={false}/><Field label="العنوان" name="address" required={false}/><div className="two-col"><Field label="خط العرض" name="latitude" required={false}/><Field label="خط الطول" name="longitude" required={false}/></div><Btn busy={busy==='/api/management/branches'} label="إضافة الفرع" icon={Plus}/></form></Panel><Panel title="الفروع الحالية">{rows.length?<div className="card-list">{rows.map((x:Row)=><div className="entity-card" key={x.id}><div className="entity-icon"><MapPin/></div><div className="entity-main"><b>{x.name}</b><small>{x.address||'بدون عنوان'}{x.phone?` · ${x.phone}`:''}{x.manager_name?` · المدير: ${x.manager_name}`:''}</small></div><span className={`badge ${x.is_active?'success':'muted-badge'}`}>{x.is_active?'فعال':'موقوف'}</span><div className="button-row"><Btn label="تعديل" icon={Pencil} variant="secondary" onClick={()=>setEditing(x)}/><Btn busy={busy===`branch-${x.id}`} label={x.is_active?'إيقاف':'تفعيل'} variant="secondary" onClick={()=>toggle(x)}/></div></div>)}</div>:<Empty/>}</Panel>{editing&&<Modal title="تعديل الفرع" onClose={()=>setEditing(null)}><form className="form-grid" onSubmit={update}><Field label="اسم الفرع" name="name" defaultValue={editing.name}/><Field label="الهاتف" name="phone" defaultValue={editing.phone||''} required={false}/><Field label="مدير الفرع" name="manager_name" defaultValue={editing.manager_name||''} required={false}/><Field label="العنوان" name="address" defaultValue={editing.address||''} required={false}/><div className="two-col"><Field label="خط العرض" name="latitude" defaultValue={editing.latitude||''} required={false}/><Field label="خط الطول" name="longitude" defaultValue={editing.longitude||''} required={false}/></div><div className="button-row"><Btn busy={busy===`edit-branch-${editing.id}`} label="حفظ"/><Btn type="button" label="إلغاء" variant="secondary" onClick={()=>setEditing(null)}/></div></form></Modal>}</div>
}

function Customers({rows,rewards,coupons,branches,brand,submit,busy,loyaltyAction,issuePass,run,reload}:any){
  const [search,setSearch]=useState('')
  const [editing,setEditing]=useState<Row|null>(null)
  const [profile,setProfile]=useState<Row|null>(null)
  const [ledger,setLedger]=useState<Row[]>([])
  const [rewardCustomer,setRewardCustomer]=useState<Row|null>(null)
  const [couponCustomer,setCouponCustomer]=useState<Row|null>(null)
  const shown=rows.filter((x:Row)=>`${x.name} ${x.phone} ${x.email||''} ${x.membership_code}`.toLowerCase().includes(search.toLowerCase()))
  const branchName=(id?:string|null)=>branches.find((x:Row)=>x.id===id)?.name||'غير مرتبط بفرع'

  async function update(e:React.FormEvent<HTMLFormElement>){
    e.preventDefault();if(!editing)return
    const fd=new FormData(e.currentTarget)
    await run(`edit-customer-${editing.id}`,()=>api(`/api/customers/${editing.id}`,{method:'PATCH',body:JSON.stringify({
      name:fd.get('name'),phone:fd.get('phone'),email:fd.get('email')||null,
      birthday:fd.get('birthday')||null,home_branch_id:fd.get('home_branch_id')||null,
      notes:fd.get('notes')||null,is_active:fd.get('is_active')==='on'
    })}),'تم تحديث العميل')
    setEditing(null);await reload()
  }
  async function openProfile(c:Row){setProfile(c);setLedger(await run(`ledger-${c.id}`,()=>api(`/api/customers/${c.id}/ledger`)))}
  async function redeem(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!rewardCustomer)return;const fd=new FormData(e.currentTarget);await run(`redeem-${rewardCustomer.id}`,()=>api(`/api/customers/${rewardCustomer.id}/redeem`,{method:'POST',body:JSON.stringify({reward_id:fd.get('reward_id'),idempotency_key:crypto.randomUUID()})}),'تم استبدال المكافأة');setRewardCustomer(null);await reload()}
  async function redeemEarned(c:Row){await run(`earned-${c.id}`,()=>api(`/api/customers/${c.id}/redeem-earned`,{method:'POST',body:JSON.stringify({idempotency_key:crypto.randomUUID()})}),'تم صرف المكافأة الجاهزة');await reload()}
  async function redeemCoupon(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!couponCustomer)return;const fd=new FormData(e.currentTarget);await run(`coupon-${couponCustomer.id}`,()=>api(`/api/customers/${couponCustomer.id}/coupons/redeem`,{method:'POST',body:JSON.stringify({code:fd.get('code'),idempotency_key:crypto.randomUUID()})}),'تم تطبيق الكوبون');setCouponCustomer(null);await reload()}
  async function reverse(tx:Row){const reason=prompt('اكتب سبب عكس العملية');if(!reason)return;await run(`reverse-${tx.id}`,()=>api(`/api/customers/transactions/${tx.id}/reverse`,{method:'POST',body:JSON.stringify({reason,idempotency_key:crypto.randomUUID()})}),'تم عكس العملية');if(profile)await openProfile(profile);await reload()}

  return <div className="wide-grid mt-6">
    <Panel title="تسجيل عميل" desc="يمكن ربط العميل بفرعه المعتاد لاستخدامه في الحملات المستهدفة">
      <form className="form-grid" onSubmit={(e)=>submit('/api/customers',e,{brand_id:brand},'POST','تم تسجيل العميل')}>
        <Field label="اسم العميل" name="name"/><Field label="رقم الهاتف" name="phone"/>
        <Field label="البريد الإلكتروني" name="email" type="email" required={false}/>
        <Field label="تاريخ الميلاد" name="birthday" type="date" required={false}/>
        <Field label="الفرع المعتاد" required={false}><select className="input" name="home_branch_id"><option value="">بدون فرع محدد</option>{branches.filter((x:Row)=>x.is_active).map((x:Row)=><option key={x.id} value={x.id}>{x.name}</option>)}</select></Field>
        <Field label="ملاحظات" name="notes" required={false}/>
        <Btn busy={busy==='/api/customers'} label="إضافة العميل" icon={Plus}/>
      </form>
    </Panel>
    <Panel title="قاعدة العملاء" action={<input className="input search-input" placeholder="بحث بالاسم أو الهاتف أو رقم العضوية" value={search} onChange={e=>setSearch(e.target.value)}/> }>
      {shown.length?<div className="customer-list">{shown.map((c:Row)=><div className="customer-card" key={c.id}>
        <div className="customer-top"><div className="avatar large">{c.name[0]}</div><div className="entity-main"><b>{c.name}</b><small>{c.phone}{c.email?` · ${c.email}`:''} · {c.membership_code} · {branchName(c.home_branch_id)}</small></div><span className="tier-pill">{c.tier}</span></div>
        <div className="mini-stats"><span><b>{c.points}</b>نقطة</span><span><b>{c.stamps}</b>ختم</span><span><b>{c.available_rewards}</b>مكافأة</span><span><b>{c.visits}</b>زيارة</span></div>
        <div className="button-row"><Btn busy={busy===`loyalty-${c.id}`} label="زيارة" icon={Plus} onClick={()=>loyaltyAction(c,'visit')}/><Btn busy={busy===`loyalty-${c.id}`} label="فاتورة" icon={CreditCard} variant="secondary" onClick={()=>loyaltyAction(c,'spend')}/><Btn busy={busy===`loyalty-${c.id}`} label="تعديل رصيد" icon={Pencil} variant="secondary" onClick={()=>loyaltyAction(c,'manual')}/><Btn label="الملف والسجل" icon={Activity} variant="secondary" onClick={()=>openProfile(c)}/><Btn label="بيانات العميل" icon={Pencil} variant="secondary" onClick={()=>setEditing(c)}/><Btn busy={busy===`pass-${c.id}`} label="إصدار Wallet" icon={WalletCards} variant="secondary" onClick={()=>issuePass(c)}/>{rewards.length>0&&<Btn label="مكافأة نقاط" icon={Gift} variant="secondary" onClick={()=>setRewardCustomer(c)}/>} {c.available_rewards>0&&<Btn busy={busy===`earned-${c.id}`} label="صرف الجاهزة" icon={Gift} variant="secondary" onClick={()=>redeemEarned(c)}/>} {coupons.length>0&&<Btn label="تطبيق كوبون" icon={Stamp} variant="secondary" onClick={()=>setCouponCustomer(c)}/>}</div>
      </div>)}</div>:<Empty text="لا يوجد عملاء مطابقون"/>}
    </Panel>
    {editing&&<Modal title="تعديل بيانات العميل" onClose={()=>setEditing(null)}><form className="form-grid" onSubmit={update}><Field label="الاسم" name="name" defaultValue={editing.name}/><Field label="الهاتف" name="phone" defaultValue={editing.phone}/><Field label="البريد" name="email" type="email" defaultValue={editing.email||''} required={false}/><Field label="تاريخ الميلاد" name="birthday" type="date" defaultValue={editing.birthday||''} required={false}/><Field label="الفرع المعتاد" required={false}><select className="input" name="home_branch_id" defaultValue={editing.home_branch_id||''}><option value="">بدون فرع محدد</option>{branches.filter((x:Row)=>x.is_active).map((x:Row)=><option key={x.id} value={x.id}>{x.name}</option>)}</select></Field><Field label="الملاحظات"><textarea className="input min-h-24" name="notes" defaultValue={editing.notes||''}/></Field><Switch label="الحساب فعال" name="is_active" defaultChecked={editing.is_active}/><div className="button-row"><Btn busy={busy===`edit-customer-${editing.id}`} label="حفظ"/><Btn type="button" label="إلغاء" variant="secondary" onClick={()=>setEditing(null)}/></div></form></Modal>}
    {rewardCustomer&&<Modal title={`استبدال مكافأة لـ ${rewardCustomer.name}`} onClose={()=>setRewardCustomer(null)}><form className="form-grid" onSubmit={redeem}><Field label="المكافأة"><select className="input" name="reward_id" required>{rewards.filter((r:Row)=>r.is_active).map((r:Row)=><option key={r.id} value={r.id}>{r.name} — {r.points_cost} نقطة {r.stock==null?'':`— المتبقي ${r.stock}`}</option>)}</select></Field><Btn busy={busy===`redeem-${rewardCustomer.id}`} label="تأكيد الاستبدال" icon={Gift}/></form></Modal>}
    {couponCustomer&&<Modal title={`تطبيق كوبون لـ ${couponCustomer.name}`} onClose={()=>setCouponCustomer(null)}><form className="form-grid" onSubmit={redeemCoupon}><Field label="رمز الكوبون"><select className="input" name="code" required>{coupons.filter((c:Row)=>c.is_active).map((c:Row)=><option key={c.id} value={c.code}>{c.code} — {c.name}</option>)}</select></Field><Btn busy={busy===`coupon-${couponCustomer.id}`} label="تطبيق الكوبون" icon={Stamp}/></form></Modal>}
    {profile&&<Modal title={`ملف ${profile.name}`} desc={`${profile.points} نقطة · ${profile.stamps} ختم · ${profile.available_rewards} مكافأة`} onClose={()=>{setProfile(null);setLedger([])}}><div className="profile-summary"><Info label="رقم العضوية" value={profile.membership_code}/><Info label="الفرع المعتاد" value={branchName(profile.home_branch_id)}/><Info label="إجمالي الصرف" value={`${Number(profile.total_spend).toLocaleString('ar-QA')} QAR`}/><Info label="آخر زيارة" value={profile.last_visit_at?new Date(profile.last_visit_at).toLocaleString('ar-QA'):'لا توجد'}/></div><h3 className="section-title">دفتر العمليات</h3><div className="ledger-list">{ledger.map((tx:Row)=><div key={tx.id}><div><b>{actionName(tx.action)}</b><small>{new Date(tx.created_at).toLocaleString('ar-QA')} · {tx.reference||'بدون مرجع'}</small></div><span className={tx.delta_points>=0?'positive':'negative'}>{tx.delta_points>=0?'+':''}{tx.delta_points} نقطة · {tx.delta_stamps>=0?'+':''}{tx.delta_stamps} ختم</span>{!['reversal','points_expired'].includes(tx.action)&&<button className="text-btn" onClick={()=>reverse(tx)}>عكس</button>}</div>)}{!ledger.length&&<Empty text="لا توجد عمليات"/>}</div></Modal>}
  </div>
}
function Staff({rows,branches,brand,submit,busy,run,reload}:any){
  const [editing,setEditing]=useState<Row|null>(null)
  async function toggle(x:Row){await run(`staff-${x.id}`,()=>api(`/api/management/staff/${x.id}`,{method:'PATCH',body:JSON.stringify({is_active:!x.is_active})}),x.is_active?'تم إيقاف الحساب':'تم تفعيل الحساب');await reload()}
  async function update(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!editing)return;const fd=new FormData(e.currentTarget);const password=String(fd.get('password')||'');const body:Row={name:fd.get('name'),phone:fd.get('phone')||null,role:fd.get('role'),branch_id:fd.get('branch_id')||null,is_active:fd.get('is_active')==='on'};if(password)body.password=password;await run(`edit-staff-${editing.id}`,()=>api(`/api/management/staff/${editing.id}`,{method:'PATCH',body:JSON.stringify(body)}),'تم تحديث الحساب والصلاحيات');setEditing(null);await reload()}
  return <div className="content-grid mt-6"><Panel title="إضافة مدير أو موظف" desc="يتم إنشاء حساب دخول حقيقي وربطه بهذا البراند"><form className="form-grid" onSubmit={(e)=>submit('/api/management/staff',e,{brand_id:brand,permissions:{}},'POST','تم إنشاء حساب الموظف')}><Field label="الاسم" name="name"/><Field label="البريد" name="email" type="email"/><Field label="الهاتف" name="phone" required={false}/><Field label="كلمة المرور" name="password" type="password" minLength={8}/><Field label="الدور"><select className="input" name="role"><option value="brand_admin">مدير البراند</option><option value="manager">مدير فرع</option><option value="employee">موظف</option></select></Field><Field label="الفرع" required={false}><select className="input" name="branch_id"><option value="">جميع الفروع</option>{branches.map((x:Row)=><option key={x.id} value={x.id}>{x.name}</option>)}</select></Field><Btn busy={busy==='/api/management/staff'} label="إنشاء الحساب" icon={UserCog}/></form></Panel><Panel title="الفريق والصلاحيات">{rows.length?<div className="card-list">{rows.map((x:Row)=><div className="entity-card" key={x.id}><div className="avatar">{x.name[0]}</div><div className="entity-main"><b>{x.name}</b><small>{x.email} · {roleName(x.role)} · {branches.find((b:Row)=>b.id===x.branch_id)?.name||'جميع الفروع'}</small></div><span className={`badge ${x.is_active?'success':'muted-badge'}`}>{x.is_active?'فعال':'موقوف'}</span><div className="button-row"><Btn label="تعديل" icon={Pencil} variant="secondary" onClick={()=>setEditing(x)}/><Btn busy={busy===`staff-${x.id}`} label={x.is_active?'إيقاف':'تفعيل'} variant="secondary" onClick={()=>toggle(x)}/></div></div>)}</div>:<Empty/>}</Panel>{editing&&<Modal title="تعديل حساب الموظف" desc="ترك كلمة المرور فارغة يبقيها كما هي" onClose={()=>setEditing(null)}><form className="form-grid" onSubmit={update}><Field label="الاسم" name="name" defaultValue={editing.name}/><Field label="الهاتف" name="phone" defaultValue={editing.phone||''} required={false}/><Field label="الدور"><select className="input" name="role" defaultValue={editing.role}><option value="brand_admin">مدير البراند</option><option value="manager">مدير فرع</option><option value="employee">موظف</option></select></Field><Field label="الفرع" required={false}><select className="input" name="branch_id" defaultValue={editing.branch_id||''}><option value="">جميع الفروع</option>{branches.map((x:Row)=><option key={x.id} value={x.id}>{x.name}</option>)}</select></Field><Field label="كلمة مرور جديدة" name="password" type="password" required={false} minLength={8}/><Switch label="الحساب فعال" name="is_active" defaultChecked={editing.is_active}/><div className="button-row"><Btn busy={busy===`edit-staff-${editing.id}`} label="حفظ"/><Btn type="button" label="إلغاء" variant="secondary" onClick={()=>setEditing(null)}/></div></form></Modal>}</div>
}

function Loyalty({program,tiers,rewards,coupons,branches,brand,busy,run,reload,submit}:any){
  const [p,setP]=useState<any>(program),[editTier,setEditTier]=useState<Row|null>(null),[editReward,setEditReward]=useState<Row|null>(null),[editCoupon,setEditCoupon]=useState<Row|null>(null)
  useEffect(()=>setP({...emptyProgram,...program,rules:{...emptyProgram.rules,...(program.rules||{})}}),[program])
  async function persistProgram(){await run('program-save',()=>api(`/api/customers/program/${brand}`,{method:'PUT',body:JSON.stringify(p)}),'تم تحديث محرك الولاء');await reload()}
  async function save(e:React.FormEvent){e.preventDefault();await persistProgram()}
  function setWeekdayMultiplier(day:string,value:number){setP({...p,rules:{...(p.rules||{}),weekday_multipliers:{...(p.rules?.weekday_multipliers||{}),[day]:value}}})}
  function setBranchMultiplier(branchId:string,value:number){setP({...p,rules:{...(p.rules||{}),branch_multipliers:{...(p.rules?.branch_multipliers||{}),[branchId]:value}}})}
  function updateHappyHour(index:number,key:string,value:string|number){const hours=[...(p.rules?.happy_hours||[])];hours[index]={...hours[index],[key]:value};setP({...p,rules:{...(p.rules||{}),happy_hours:hours}})}
  function addHappyHour(){setP({...p,rules:{...(p.rules||{}),happy_hours:[...(p.rules?.happy_hours||[]),{start:'14:00',end:'17:00',multiplier:2}]}})}
  function removeHappyHour(index:number){setP({...p,rules:{...(p.rules||{}),happy_hours:(p.rules?.happy_hours||[]).filter((_:any,i:number)=>i!==index)}})}
  async function updateTier(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!editTier)return;const fd=new FormData(e.currentTarget);await run(`tier-edit-${editTier.id}`,()=>api(`/api/management/tiers/${editTier.id}`,{method:'PATCH',body:JSON.stringify({name:fd.get('name'),rank:Number(fd.get('rank')),color:fd.get('color'),min_points:Number(fd.get('min_points')),min_spend:Number(fd.get('min_spend')),points_multiplier:Number(fd.get('points_multiplier')),is_active:fd.get('is_active')==='on'})}),'تم تحديث المستوى');setEditTier(null);await reload()}
  async function updateReward(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!editReward)return;const fd=new FormData(e.currentTarget);await run(`reward-edit-${editReward.id}`,()=>api(`/api/management/rewards/${editReward.id}`,{method:'PATCH',body:JSON.stringify({name:fd.get('name'),description:fd.get('description')||null,points_cost:Number(fd.get('points_cost')),stock:fd.get('stock')===''?null:Number(fd.get('stock')),is_active:fd.get('is_active')==='on'})}),'تم تحديث المكافأة');setEditReward(null);await reload()}
  async function updateCoupon(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!editCoupon)return;const fd=new FormData(e.currentTarget);await run(`coupon-edit-${editCoupon.id}`,()=>api(`/api/management/coupons/${editCoupon.id}`,{method:'PATCH',body:JSON.stringify({name:fd.get('name'),description:fd.get('description')||null,reward_type:fd.get('reward_type'),reward_value:Number(fd.get('reward_value')),starts_at:fd.get('starts_at')?new Date(String(fd.get('starts_at'))).toISOString():null,ends_at:fd.get('ends_at')?new Date(String(fd.get('ends_at'))).toISOString():null,max_redemptions:fd.get('max_redemptions')===''?null:Number(fd.get('max_redemptions')),per_customer_limit:Number(fd.get('per_customer_limit')),is_active:fd.get('is_active')==='on'})}),'تم تحديث الكوبون');setEditCoupon(null);await reload()}
  return <><div className="content-grid mt-6"><Panel title="قواعد محرك الولاء" desc="تطبق من السيرفر على كل عملية ولا يحددها جهاز الموظف"><form className="form-grid" onSubmit={save}><Field label="نوع البرنامج"><select className="input" value={p.program_type} onChange={e=>setP({...p,program_type:e.target.value})}><option value="points">نقاط</option><option value="stamps">أختام</option><option value="hybrid">نقاط وأختام</option><option value="cashback">Cashback كنقاط</option></select></Field><div className="two-col"><NumberInput label="نقاط كل زيارة" value={p.points_per_visit} onChange={(v:number)=>setP({...p,points_per_visit:v})}/><NumberInput label="نقاط كل وحدة عملة" value={p.points_per_currency} onChange={(v:number)=>setP({...p,points_per_currency:v})}/></div><div className="two-col"><NumberInput label="عدد الأختام للمكافأة" value={p.required_stamps} min={1} onChange={(v:number)=>setP({...p,required_stamps:v})}/><Field label="اسم مكافأة الأختام"><input className="input" value={p.stamp_reward_title} onChange={e=>setP({...p,stamp_reward_title:e.target.value})}/></Field></div><div className="two-col"><NumberInput label="نقاط المكافأة التلقائية" value={p.reward_points} min={1} onChange={(v:number)=>setP({...p,reward_points:v})}/><Field label="اسم مكافأة النقاط"><input className="input" value={p.reward_title} onChange={e=>setP({...p,reward_title:e.target.value})}/></Field></div><div className="two-col"><NumberInput label="مكافأة عيد الميلاد" value={p.birthday_bonus} onChange={(v:number)=>setP({...p,birthday_bonus:v})}/><NumberInput label="مكافأة الإحالة" value={p.referral_bonus} onChange={(v:number)=>setP({...p,referral_bonus:v})}/></div><div className="two-col"><NumberInput label="نسبة Cashback %" value={p.cashback_percent} onChange={(v:number)=>setP({...p,cashback_percent:v})}/><NumberInput label="مضاعف النقاط العام" value={p.rules?.global_multiplier??1} min={1} onChange={(v:number)=>setP({...p,rules:{...(p.rules||{}),global_multiplier:v}})}/></div><div className="two-col"><NumberInput label="انتهاء النقاط بعد (يوم)" value={p.points_expiry_days??''} required={false} onChange={(v:any)=>setP({...p,points_expiry_days:v===''?null:v})}/><NumberInput label="الحد اليومي للنقاط" value={p.daily_points_cap??''} required={false} onChange={(v:any)=>setP({...p,daily_points_cap:v===''?null:v})}/></div><label className="switch-row"><input type="checkbox" checked={p.enabled} onChange={e=>setP({...p,enabled:e.target.checked})}/><span>تشغيل برنامج الولاء</span></label><label className="switch-row"><input type="checkbox" checked={p.allow_manual_adjustment} onChange={e=>setP({...p,allow_manual_adjustment:e.target.checked})}/><span>السماح بالتعديل اليدوي</span></label><label className="switch-row"><input type="checkbox" checked={!!p.rules?.auto_convert_points} onChange={e=>setP({...p,rules:{...(p.rules||{}),auto_convert_points:e.target.checked}})}/><span>تحويل النقاط إلى مكافأة تلقائيًا</span></label><Btn busy={busy==='program-save'} label="حفظ قواعد الولاء"/></form></Panel><Panel title="ملخص القواعد النشطة"><div className="rule-summary"><Rule icon={Gift} title={`${p.points_per_visit} نقطة`} text="لكل زيارة"/><Rule icon={CreditCard} title={`${p.points_per_currency} نقطة`} text="لكل وحدة عملة"/><Rule icon={Stamp} title={`${p.required_stamps} أختام`} text={p.stamp_reward_title}/><Rule icon={Sparkles} title={`× ${p.rules?.global_multiplier||1}`} text="المضاعف العام"/><Rule icon={Gift} title={`${p.birthday_bonus} نقطة`} text="مكافأة الميلاد"/><Rule icon={Activity} title={p.points_expiry_days?`${p.points_expiry_days} يوم`:'بدون انتهاء'} text="صلاحية النقاط"/></div></Panel></div>
  <Panel title="المضاعفات الذكية" desc="يمكن تطبيق مضاعفات حسب اليوم أو الفرع أو نافذة زمنية، ويحسبها السيرفر تلقائيًا" className="mt-5"><div className="form-grid"><div className="form-divider">مضاعفات أيام الأسبوع</div><div className="weekday-grid">{[['0','الاثنين'],['1','الثلاثاء'],['2','الأربعاء'],['3','الخميس'],['4','الجمعة'],['5','السبت'],['6','الأحد']].map(([key,label])=><label className="field" key={key}><span>{label}</span><input className="input" type="number" min="1" max="20" step="0.1" value={p.rules?.weekday_multipliers?.[key]??1} onChange={e=>setWeekdayMultiplier(key,Number(e.target.value||1))}/></label>)}</div><div className="form-divider">مضاعفات الفروع</div>{branches.length?<div className="weekday-grid">{branches.filter((x:Row)=>x.is_active).map((x:Row)=><label className="field" key={x.id}><span>{x.name}</span><input className="input" type="number" min="1" max="20" step="0.1" value={p.rules?.branch_multipliers?.[x.id]??1} onChange={e=>setBranchMultiplier(x.id,Number(e.target.value||1))}/></label>)}</div>:<p className="muted text-sm">أنشئ فرعًا أولًا لإضافة مضاعف خاص به.</p>}<div className="form-divider">الساعات المضاعفة</div><div className="happy-hour-list">{(p.rules?.happy_hours||[]).map((window:Row,index:number)=><div className="happy-hour-row" key={index}><Field label="من"><input className="input" type="time" value={window.start||''} onChange={e=>updateHappyHour(index,'start',e.target.value)}/></Field><Field label="إلى"><input className="input" type="time" value={window.end||''} onChange={e=>updateHappyHour(index,'end',e.target.value)}/></Field><Field label="المضاعف"><input className="input" type="number" min="1" max="20" step="0.1" value={window.multiplier||1} onChange={e=>updateHappyHour(index,'multiplier',Number(e.target.value||1))}/></Field><Btn type="button" label="حذف" icon={XCircle} variant="secondary" onClick={()=>removeHappyHour(index)}/></div>)}{!(p.rules?.happy_hours||[]).length&&<p className="muted text-sm">لا توجد ساعات مضاعفة.</p>}</div><div className="button-row"><Btn type="button" label="إضافة فترة" icon={Plus} variant="secondary" onClick={addHappyHour}/><Btn type="button" busy={busy==='program-save'} label="حفظ المضاعفات" onClick={persistProgram}/></div></div></Panel>
  <div className="triple-grid mt-5"><Panel title="المستويات"><form className="form-grid compact-form" onSubmit={(e)=>submit('/api/management/tiers',e,{brand_id:brand,benefits:{}},'POST','تم إنشاء المستوى')}><Field label="الاسم" name="name"/><div className="two-col"><Field label="الترتيب" name="rank" type="number" defaultValue="0"/><Field label="اللون" name="color" type="color" defaultValue="#C6FF4A"/></div><div className="two-col"><Field label="أقل نقاط" name="min_points" type="number" defaultValue="0"/><Field label="أقل إنفاق" name="min_spend" type="number" defaultValue="0"/></div><Field label="مضاعف النقاط" name="points_multiplier" type="number" defaultValue="1" min="1"/><Btn busy={busy==='/api/management/tiers'} label="إضافة مستوى" icon={Plus}/></form><div className="compact-list mt-list">{tiers.map((x:Row)=><div key={x.id}><span className="color-dot" style={{background:x.color}}/><div className="entity-main"><b>{x.name}</b><small>من {x.min_points} نقطة · ×{x.points_multiplier}</small></div><button className="text-btn" onClick={()=>setEditTier(x)}>تعديل</button></div>)}</div></Panel>
  <Panel title="المكافآت"><form className="form-grid compact-form" onSubmit={(e)=>submit('/api/management/rewards',e,{brand_id:brand},'POST','تم إنشاء المكافأة')}><Field label="اسم المكافأة" name="name"/><Field label="الوصف" name="description" required={false}/><div className="two-col"><Field label="تكلفة النقاط" name="points_cost" type="number" defaultValue="100"/><Field label="المخزون" name="stock" type="number" required={false}/></div><Btn busy={busy==='/api/management/rewards'} label="إضافة مكافأة" icon={Plus}/></form><div className="compact-list mt-list">{rewards.map((x:Row)=><div key={x.id}><Gift/><div className="entity-main"><b>{x.name}</b><small>{x.points_cost} نقطة · المخزون {x.stock??'مفتوح'}</small></div><button className="text-btn" onClick={()=>setEditReward(x)}>تعديل</button></div>)}</div></Panel>
  <Panel title="الكوبونات"><form className="form-grid compact-form" onSubmit={(e)=>submit('/api/management/coupons',e,{brand_id:brand},'POST','تم إنشاء الكوبون')}><div className="two-col"><Field label="الرمز" name="code" placeholder="WELCOME20"/><Field label="الاسم" name="name"/></div><Field label="نوع الميزة"><select className="input" name="reward_type"><option value="points">نقاط</option><option value="stamps">أختام</option><option value="discount_percent">خصم نسبة</option><option value="discount_amount">خصم مبلغ</option><option value="free_item">منتج مجاني</option></select></Field><div className="two-col"><Field label="القيمة" name="reward_value" type="number" defaultValue="10"/><Field label="حد كل عميل" name="per_customer_limit" type="number" defaultValue="1"/></div><div className="two-col"><Field label="يبدأ في" name="starts_at" type="datetime-local" required={false}/><Field label="ينتهي في" name="ends_at" type="datetime-local" required={false}/></div><Field label="إجمالي مرات الاستخدام" name="max_redemptions" type="number" required={false}/><Btn busy={busy==='/api/management/coupons'} label="إنشاء كوبون" icon={Stamp}/></form><div className="compact-list mt-list">{coupons.map((x:Row)=><div key={x.id}><Stamp/><div className="entity-main"><b>{x.code} · {x.name}</b><small>{couponTypeName(x.reward_type)} {x.reward_value} · استخدم {x.redemption_count}</small></div><button className="text-btn" onClick={()=>setEditCoupon(x)}>تعديل</button></div>)}</div></Panel></div>
  {editTier&&<Modal title="تعديل المستوى" onClose={()=>setEditTier(null)}><form className="form-grid" onSubmit={updateTier}><Field label="الاسم" name="name" defaultValue={editTier.name}/><Field label="الترتيب" name="rank" type="number" defaultValue={editTier.rank}/><Field label="اللون" name="color" type="color" defaultValue={editTier.color}/><Field label="أقل نقاط" name="min_points" type="number" defaultValue={editTier.min_points}/><Field label="أقل إنفاق" name="min_spend" type="number" defaultValue={editTier.min_spend}/><Field label="المضاعف" name="points_multiplier" type="number" defaultValue={editTier.points_multiplier}/><Switch label="المستوى فعال" name="is_active" defaultChecked={editTier.is_active}/><Btn busy={busy===`tier-edit-${editTier.id}`} label="حفظ"/></form></Modal>}
  {editReward&&<Modal title="تعديل المكافأة" onClose={()=>setEditReward(null)}><form className="form-grid" onSubmit={updateReward}><Field label="الاسم" name="name" defaultValue={editReward.name}/><Field label="الوصف" name="description" defaultValue={editReward.description||''} required={false}/><Field label="تكلفة النقاط" name="points_cost" type="number" defaultValue={editReward.points_cost}/><Field label="المخزون" name="stock" type="number" defaultValue={editReward.stock??''} required={false}/><Switch label="المكافأة فعالة" name="is_active" defaultChecked={editReward.is_active}/><Btn busy={busy===`reward-edit-${editReward.id}`} label="حفظ"/></form></Modal>}
  {editCoupon&&<Modal title="تعديل الكوبون" onClose={()=>setEditCoupon(null)}><form className="form-grid" onSubmit={updateCoupon}><Field label="الاسم" name="name" defaultValue={editCoupon.name}/><Field label="الوصف" name="description" defaultValue={editCoupon.description||''} required={false}/><Field label="نوع الميزة"><select className="input" name="reward_type" defaultValue={editCoupon.reward_type}><option value="points">نقاط</option><option value="stamps">أختام</option><option value="discount_percent">خصم نسبة</option><option value="discount_amount">خصم مبلغ</option><option value="free_item">منتج مجاني</option></select></Field><Field label="القيمة" name="reward_value" type="number" defaultValue={editCoupon.reward_value}/><div className="two-col"><Field label="يبدأ في" name="starts_at" type="datetime-local" defaultValue={dateTimeInput(editCoupon.starts_at)} required={false}/><Field label="ينتهي في" name="ends_at" type="datetime-local" defaultValue={dateTimeInput(editCoupon.ends_at)} required={false}/></div><Field label="إجمالي مرات الاستخدام" name="max_redemptions" type="number" defaultValue={editCoupon.max_redemptions??''} required={false}/><Field label="حد كل عميل" name="per_customer_limit" type="number" defaultValue={editCoupon.per_customer_limit}/><Switch label="الكوبون فعال" name="is_active" defaultChecked={editCoupon.is_active}/><Btn busy={busy===`coupon-edit-${editCoupon.id}`} label="حفظ"/></form></Modal>}
  </>
}

function WalletStudio({design,customers,brand,brandInfo,busy,run,reload,issuePass}:any){const [d,setD]=useState<any>({...emptyDesign,...design,fields:{...emptyDesign.fields,...(design.fields||{})}});useEffect(()=>setD({...emptyDesign,...design,fields:{...emptyDesign.fields,...(design.fields||{})}}),[design]);async function save(){await run('design-save',()=>api(`/api/wallet/design/${brand}`,{method:'PUT',body:JSON.stringify(d)}),'تم حفظ مسودة التصميم');reload()}async function publish(){await run('design-publish',()=>api(`/api/wallet/design/${brand}/publish`,{method:'POST'}),'تم نشر التصميم وتحديد البطاقات للتحديث');reload()}async function asset(e:React.ChangeEvent<HTMLInputElement>,kind:'logo'|'hero'){const file=e.target.files?.[0];if(!file)return;const fd=new FormData();fd.append('kind',kind);fd.append('file',file);await run(`asset-${kind}`,()=>api(`/api/wallet/design/${brand}/asset`,{method:'POST',body:fd}),kind==='logo'?'تم رفع شعار البطاقة':'تم رفع صورة البطاقة');e.target.value='';reload()}return <div className="studio-grid mt-6"><Panel title="إعدادات التصميم" desc="الشهادة لا تظهر لمدير البراند؛ التصميم فقط"><div className="form-grid"><ColorInput label="الخلفية" value={d.background_color} onChange={(v:string)=>setD({...d,background_color:v})}/><ColorInput label="النص" value={d.foreground_color} onChange={(v:string)=>setD({...d,foreground_color:v})}/><ColorInput label="العناوين" value={d.label_color} onChange={(v:string)=>setD({...d,label_color:v})}/><Field label="اسم الشعار"><input className="input" value={d.logo_text} onChange={e=>setD({...d,logo_text:e.target.value})}/></Field><Field label="عنوان البطاقة"><input className="input" value={d.card_title} onChange={e=>setD({...d,card_title:e.target.value})}/></Field><div className="asset-grid"><label className="asset-upload"><Upload size={18}/><span>{busy==='asset-logo'?'جاري رفع الشعار...':'رفع شعار البطاقة'}</span><input type="file" accept="image/png,image/jpeg,image/webp" onChange={e=>asset(e,'logo')} disabled={busy==='asset-logo'}/></label><label className="asset-upload"><Upload size={18}/><span>{busy==='asset-hero'?'جاري رفع الصورة...':'رفع الصورة العلوية'}</span><input type="file" accept="image/png,image/jpeg,image/webp" onChange={e=>asset(e,'hero')} disabled={busy==='asset-hero'}/></label></div><Field label="نوع الباركود"><select className="input" value={d.barcode_format} onChange={e=>setD({...d,barcode_format:e.target.value})}><option value="PKBarcodeFormatQR">QR</option><option value="PKBarcodeFormatPDF417">PDF417</option><option value="PKBarcodeFormatAztec">Aztec</option><option value="PKBarcodeFormatCode128">Code 128</option></select></Field><Field label="الشروط والأحكام" required={false}><textarea className="input min-h-24" value={d.terms||''} onChange={e=>setD({...d,terms:e.target.value})}/></Field><div className="switch-grid">{[['show_points','إظهار النقاط'],['show_stamps','إظهار الأختام'],['show_rewards','إظهار المكافآت'],['show_tier','إظهار المستوى'],['show_visits','إظهار الزيارات']].map(([key,label])=><label className="switch-row" key={key}><input type="checkbox" checked={!!d.fields[key]} onChange={e=>setD({...d,fields:{...d.fields,[key]:e.target.checked}})}/><span>{label}</span></label>)}</div><div className="button-row"><Btn busy={busy==='design-save'} label="حفظ المسودة" onClick={save}/><Btn busy={busy==='design-publish'} label="نشر التصميم" icon={Upload} variant="secondary" onClick={publish}/></div><p className="muted text-sm">المسودة: {d.draft_version||1} · المنشور: {d.published_version||0} · {d.is_published?'التصميم منشور':'غير منشور'}</p></div></Panel><div className="studio-side"><Panel title="معاينة فورية"><WalletCard design={d} brand={brandInfo}/></Panel><Panel title="إصدار بطاقات العملاء" desc="بعد نشر التصميم، اختر عميلًا لإصدار الرابط"><div className="compact-list scroll-list">{customers.map((c:Row)=><div key={c.id}><div className="entity-main"><b>{c.name}</b><small>{c.points} نقطة · {c.tier}</small></div><Btn busy={busy===`pass-${c.id}`} label="إصدار" icon={WalletCards} variant="secondary" onClick={()=>issuePass(c)}/></div>)}{!customers.length&&<Empty/>}</div></Panel></div></div>}

function Campaigns({rows,templates,customers,branches,brand,busy,run,reload}:any){
  const [name,setName]=useState('')
  const [title,setTitle]=useState('')
  const [body,setBody]=useState('')
  const [channel,setChannel]=useState('in_app')
  const [audience,setAudience]=useState('all')
  const [filter,setFilter]=useState('')
  const [selectedCustomers,setSelectedCustomers]=useState<string[]>([])
  const [recurrence,setRecurrence]=useState('none')
  const [editing,setEditing]=useState<Row|null>(null)

  function chooseTemplate(id:string){const t=templates.find((x:Row)=>x.id===id);if(t){setTitle(t.title);setBody(t.body);setChannel(t.channel)}}
  function audienceFilter(){
    if(audience==='tier')return {tier:filter}
    if(audience==='min_points')return {min_points:Number(filter||0)}
    if(audience==='inactive_days')return {days:Number(filter||30)}
    if(audience==='branch')return {branch_id:filter}
    if(audience==='selected')return {customer_ids:selectedCustomers}
    return {}
  }
  function changeAudience(value:string){setAudience(value);setFilter('');setSelectedCustomers([])}
  function toggleCustomer(id:string){setSelectedCustomers(current=>current.includes(id)?current.filter(x=>x!==id):[...current,id])}
  async function create(e:React.FormEvent<HTMLFormElement>){
    e.preventDefault();const form=e.currentTarget;const fd=new FormData(form);const sendNow=fd.get('send_now')==='on';const rawSchedule=String(fd.get('scheduled_at')||'')
    await run('campaign-create',()=>api('/api/notifications/campaigns',{method:'POST',body:JSON.stringify({brand_id:brand,name,title,body,channel,audience_type:audience,audience_filter:audienceFilter(),recurrence,scheduled_at:rawSchedule?new Date(rawSchedule).toISOString():null,send_now:sendNow})}),'تم إنشاء الحملة')
    setName('');setTitle('');setBody('');setChannel('in_app');setAudience('all');setFilter('');setSelectedCustomers([]);setRecurrence('none');form.reset();await reload()
  }
  async function createTemplate(e:React.FormEvent<HTMLFormElement>){e.preventDefault();const form=e.currentTarget;const fd=new FormData(form);await run('template-create',()=>api('/api/notifications/templates',{method:'POST',body:JSON.stringify({brand_id:brand,name:fd.get('template_name'),title:fd.get('template_title'),body:fd.get('template_body'),channel:fd.get('template_channel')})}),'تم حفظ قالب الإشعار');form.reset();await reload()}
  async function send(x:Row){await run(`send-${x.id}`,()=>api(`/api/notifications/campaigns/${x.id}/send`,{method:'POST'}),'تم وضع الحملة في قائمة الإرسال');await reload()}
  async function cancel(x:Row){await run(`cancel-${x.id}`,()=>api(`/api/notifications/campaigns/${x.id}/cancel`,{method:'POST'}),'تم إلغاء الحملة');await reload()}
  async function toggleTemplate(x:Row){await run(`template-${x.id}`,()=>api(`/api/notifications/templates/${x.id}/toggle`,{method:'PATCH'}),x.is_active?'تم إيقاف القالب':'تم تفعيل القالب');await reload()}
  async function update(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!editing)return;const fd=new FormData(e.currentTarget);await run(`campaign-edit-${editing.id}`,()=>api(`/api/notifications/campaigns/${editing.id}`,{method:'PATCH',body:JSON.stringify({name:fd.get('name'),title:fd.get('title'),body:fd.get('body'),scheduled_at:fd.get('scheduled_at')?new Date(String(fd.get('scheduled_at'))).toISOString():null})}),'تم تحديث الحملة');setEditing(null);await reload()}

  return <>
    <div className="content-grid mt-6">
      <Panel title="إنشاء حملة" desc="تعمل عبر Worker مستقل ولا تظهر ناجحة إلا بعد التسليم الفعلي">
        <form className="form-grid" onSubmit={create}>
          {templates.length>0&&<Field label="استخدام قالب محفوظ" required={false}><select className="input" defaultValue="" onChange={e=>chooseTemplate(e.target.value)}><option value="">بدون قالب</option>{templates.filter((x:Row)=>x.is_active).map((x:Row)=><option key={x.id} value={x.id}>{x.name}</option>)}</select></Field>}
          <Field label="اسم الحملة"><input className="input" value={name} onChange={e=>setName(e.target.value)} required/></Field>
          <Field label="عنوان الرسالة"><input className="input" value={title} onChange={e=>setTitle(e.target.value)} required/></Field>
          <Field label="نص الرسالة"><textarea className="input min-h-28" value={body} onChange={e=>setBody(e.target.value)} required/></Field>
          <div className="two-col"><Field label="القناة"><select className="input" value={channel} onChange={e=>setChannel(e.target.value)}><option value="in_app">داخل صندوق العميل</option><option value="wallet_push">تحديث Apple Wallet</option><option value="email">Email</option><option value="sms">SMS</option><option value="webhook">Webhook</option></select></Field><Field label="الجمهور"><select className="input" value={audience} onChange={e=>changeAudience(e.target.value)}><option value="all">جميع العملاء</option><option value="birthday">أعياد الميلاد اليوم</option><option value="tier">مستوى محدد</option><option value="min_points">حد أدنى للنقاط</option><option value="inactive_days">غير نشطين منذ مدة</option><option value="branch">فرع محدد</option><option value="rewards_ready">لديهم مكافأة جاهزة</option><option value="selected">عملاء محددون</option></select></Field></div>
          {audience==='tier'&&<Field label="اسم المستوى"><input className="input" value={filter} onChange={e=>setFilter(e.target.value)} required/></Field>}
          {audience==='min_points'&&<Field label="الحد الأدنى للنقاط"><input className="input" type="number" min="0" value={filter} onChange={e=>setFilter(e.target.value)} required/></Field>}
          {audience==='inactive_days'&&<Field label="عدد أيام عدم النشاط"><input className="input" type="number" min="1" value={filter} onChange={e=>setFilter(e.target.value)} required/></Field>}
          {audience==='branch'&&<Field label="الفرع المستهدف"><select className="input" value={filter} onChange={e=>setFilter(e.target.value)} required><option value="">اختر الفرع</option>{branches.filter((x:Row)=>x.is_active).map((x:Row)=><option key={x.id} value={x.id}>{x.name}</option>)}</select></Field>}
          {audience==='selected'&&<Field label={`العملاء المحددون (${selectedCustomers.length})`}><div className="selection-list">{customers.filter((x:Row)=>x.is_active).map((x:Row)=><label key={x.id}><input type="checkbox" checked={selectedCustomers.includes(x.id)} onChange={()=>toggleCustomer(x.id)}/><span><b>{x.name}</b><small>{x.phone}</small></span></label>)}{!customers.length&&<p className="muted">لا يوجد عملاء داخل البراند</p>}</div></Field>}
          <div className="two-col"><Field label="وقت الإرسال" name="scheduled_at" type="datetime-local" required={false}/><Field label="التكرار"><select className="input" value={recurrence} onChange={e=>setRecurrence(e.target.value)}><option value="none">مرة واحدة</option><option value="daily">يوميًا</option><option value="weekly">أسبوعيًا</option><option value="monthly">شهريًا</option></select></Field></div>
          <Switch label="إرسال الآن بعد الحفظ" name="send_now"/>
          <Btn busy={busy==='campaign-create'} disabled={audience==='selected'&&!selectedCustomers.length} label="إنشاء الحملة" icon={Bell}/>
        </form>
      </Panel>
      <Panel title="الحملات وحالة التسليم">{rows.length?<div className="campaign-list">{rows.map((x:Row)=><div className="campaign-card" key={x.id}><div className="campaign-head"><div><b>{x.name}</b><small>{x.title} · {channelName(x.channel)} · {audienceName(x.audience_type)}</small></div><span className={`badge status-${x.status}`}>{statusName(x.status)}</span></div><div className="delivery-bar"><div style={{width:`${x.total_recipients?Math.round((x.sent_count/x.total_recipients)*100):0}%`}}/></div><div className="delivery-stats"><span>المستهدفون <b>{x.total_recipients}</b></span><span>نجح <b>{x.sent_count}</b></span><span>فشل <b>{x.failed_count}</b></span><span>تجاوز <b>{x.skipped_count}</b></span>{x.recurrence!=='none'&&<span>التكرار <b>{recurrenceName(x.recurrence)}</b></span>}</div><div className="button-row">{['draft','scheduled'].includes(x.status)&&<Btn label="تعديل" icon={Pencil} variant="secondary" onClick={()=>setEditing(x)}/>} {['draft','scheduled','queued','failed','partially_completed'].includes(x.status)&&<Btn busy={busy===`send-${x.id}`} label="إرسال الآن" icon={Send} onClick={()=>send(x)}/>} {!['completed','partially_completed','cancelled'].includes(x.status)&&<Btn busy={busy===`cancel-${x.id}`} label="إلغاء" icon={XCircle} variant="secondary" onClick={()=>cancel(x)}/>}</div></div>)}</div>:<Empty/>}</Panel>
    </div>
    <div className="content-grid mt-5"><Panel title="إنشاء قالب إشعار"><form className="form-grid" onSubmit={createTemplate}><Field label="اسم القالب" name="template_name"/><Field label="العنوان" name="template_title"/><Field label="النص"><textarea className="input min-h-24" name="template_body" required/></Field><Field label="القناة"><select className="input" name="template_channel"><option value="in_app">داخل المنصة</option><option value="wallet_push">Apple Wallet</option><option value="email">Email</option><option value="sms">SMS</option><option value="webhook">Webhook</option></select></Field><Btn busy={busy==='template-create'} label="حفظ القالب" icon={Save}/></form></Panel><Panel title="القوالب المحفوظة">{templates.length?<div className="compact-list">{templates.map((x:Row)=><div key={x.id}><Bell/><div className="entity-main"><b>{x.name}</b><small>{x.title} · {channelName(x.channel)}</small></div><button className="text-btn" onClick={()=>toggleTemplate(x)}>{x.is_active?'إيقاف':'تفعيل'}</button></div>)}</div>:<Empty/>}</Panel></div>
    {editing&&<Modal title="تعديل الحملة" desc="يمكن تعديل المسودة أو الحملة المجدولة قبل بدء الإرسال" onClose={()=>setEditing(null)}><form className="form-grid" onSubmit={update}><Field label="اسم الحملة" name="name" defaultValue={editing.name}/><Field label="العنوان" name="title" defaultValue={editing.title}/><Field label="النص"><textarea className="input min-h-28" name="body" defaultValue={editing.body}/></Field><Field label="وقت الإرسال" name="scheduled_at" type="datetime-local" required={false}/><Btn busy={busy===`campaign-edit-${editing.id}`} label="حفظ التعديل"/></form></Modal>}
  </>
}
function Audit({rows}:any){return <Panel title="سجل التدقيق" desc="آخر 300 عملية داخل البراند" className="mt-6"><div className="table-wrap"><table><thead><tr><th>الوقت</th><th>العملية</th><th>النوع</th><th>المعرف</th><th>IP</th></tr></thead><tbody>{rows.map((x:Row)=><tr key={x.id}><td>{new Date(x.created_at).toLocaleString('ar-QA')}</td><td>{actionName(x.action)}</td><td>{x.entity_type}</td><td className="mono">{x.entity_id||'—'}</td><td>{x.ip_address||'—'}</td></tr>)}</tbody></table>{!rows.length&&<Empty/>}</div></Panel>}

function PlatformWallet({credential,busy,run,reload}:any){async function upload(e:React.FormEvent<HTMLFormElement>){e.preventDefault();const form=e.currentTarget;const fd=new FormData(form);await run('cert-upload',()=>api('/api/wallet/platform/credential',{method:'POST',body:fd}),'تم التحقق من الشهادة وتفعيلها مركزيًا');form.reset();reload()}return <div className="content-grid mt-6"><Panel title="رفع الشهادة المركزية" desc="تُحفظ مشفرة في السيرفر ولا يمكن لمديري البراندات رؤيتها"><form className="form-grid" onSubmit={upload}><Field label="شهادة Pass Type (.p12)" name="p12_file" type="file" accept=".p12"/><Field label="شهادة Apple WWDR (.cer أو .pem)" name="wwdr_file" type="file" accept=".cer,.pem"/><Field label="كلمة مرور .p12" name="password" type="password"/><Field label="Pass Type Identifier" name="pass_type_identifier" placeholder="pass.com.company.loyalyn"/><Field label="Team Identifier" name="team_identifier"/><Field label="Organization Name" name="organization_name" defaultValue="Loyalyn"/><Btn busy={busy==='cert-upload'} label="تحقق وارفع الشهادة" icon={ShieldCheck}/></form></Panel><Panel title="حالة Apple Wallet">{credential?.configured?<div className="credential-card"><div className="credential-icon"><ShieldCheck/></div><h3>الشهادة مفعلة</h3><p>{credential.filename}</p><Info label="Pass Type" value={credential.pass_type_identifier}/><Info label="Team ID" value={credential.team_identifier}/><Info label="الجهة" value={credential.organization_name}/><Info label="تاريخ الانتهاء" value={credential.expires_at?new Date(credential.expires_at).toLocaleDateString('ar-QA'):'غير متاح'}/><Info label="الحالة" value={credential.status}/></div>:<div className="warning-box"><ShieldCheck/><h3>لم تُرفع الشهادة بعد</h3><p>مديرو البراندات يستطيعون التصميم، لكن لا يمكن إصدار ملف pkpass حتى ترفع الشهادة هنا.</p></div>}</Panel></div>}

function WalletCard({design,brand}:any){const hero=design.hero_url?`${API}/api/wallet/public/assets/${brand?.id}/hero`:'';const logo=design.logo_url?`${API}/api/wallet/public/assets/${brand?.id}/logo`:'';return <div className="wallet-preview" style={{background:design.background_color,color:design.foreground_color}}>{hero&&<img className="wallet-hero-image" src={hero} alt=""/>}<div className="wallet-header"><div><small style={{color:design.label_color}}>MEMBER CARD</small><h3>{design.logo_text||brand?.name}</h3></div>{logo?<img className="wallet-logo-image" src={logo} alt="شعار البراند"/>:<div className="wallet-logo">{(brand?.name||'L')[0]}</div>}</div><p className="wallet-title">{design.card_title}</p><div className="wallet-values">{design.fields.show_points&&<span><small style={{color:design.label_color}}>النقاط</small><b>1,250</b></span>}{design.fields.show_rewards&&<span><small style={{color:design.label_color}}>المكافآت</small><b>3</b></span>}{design.fields.show_stamps&&<span><small style={{color:design.label_color}}>الأختام</small><b>4 / 6</b></span>}</div><div className="wallet-footer"><span>{design.fields.show_tier?'ذهبي':''}</span><div className="qr-box">QR</div></div></div>}
function NumberInput({label,value,onChange,min=0,required=true}:any){return <label className="field"><span>{label}</span><input className="input" type="number" min={min} value={value} required={required} onChange={e=>onChange(e.target.value===''?'':Number(e.target.value))}/></label>}
function ColorInput({label,value,onChange}:any){return <label className="field"><span>{label}</span><div className="color-input"><input type="color" value={value} onChange={e=>onChange(e.target.value)}/><input className="input mono" value={value} onChange={e=>onChange(e.target.value)}/></div></label>}
function Rule({icon:Icon,title,text}:any){return <div><div className="entity-icon"><Icon/></div><b>{title}</b><span>{text}</span></div>}
function Info({label,value}:any){return <div className="info-row"><span>{label}</span><b>{value}</b></div>}
const dateTimeInput=(value:any)=>value?new Date(value).toISOString().slice(0,16):''
const actionName=(v:string)=>({visit:'زيارة',spend:'عملية شراء',manual:'تعديل يدوي',birthday:'مكافأة ميلاد',referral:'إحالة',reversal:'عكس عملية',redeem_reward:'استبدال مكافأة',brand_created:'إنشاء براند',brand_updated:'تعديل براند',customer_created:'إنشاء عميل',loyalty_applied:'تحديث ولاء',wallet_pass_issued:'إصدار بطاقة',wallet_design_published:'نشر تصميم',campaign_created:'إنشاء حملة'} as Row)[v]||v
const roleName=(v:string)=>({brand_admin:'مدير البراند',manager:'مدير فرع',employee:'موظف'} as Row)[v]||v
const channelName=(v:string)=>({in_app:'داخل المنصة',wallet_push:'Apple Wallet',email:'Email',sms:'SMS',webhook:'Webhook'} as Row)[v]||v
const audienceName=(v:string)=>({all:'الجميع',birthday:'أعياد الميلاد',tier:'مستوى محدد',min_points:'حسب النقاط',inactive_days:'غير النشطين',branch:'فرع محدد',rewards_ready:'مكافأة جاهزة',selected:'قائمة محددة'} as Row)[v]||v
const recurrenceName=(v:string)=>({none:'مرة واحدة',daily:'يومي',weekly:'أسبوعي',monthly:'شهري'} as Row)[v]||v
const couponTypeName=(v:string)=>({points:'نقاط',stamps:'أختام',discount_percent:'خصم %',discount_amount:'خصم مبلغ',free_item:'منتج مجاني'} as Row)[v]||v
const statusName=(v:string)=>({draft:'مسودة',scheduled:'مجدولة',queued:'في قائمة الإرسال',processing:'قيد الإرسال',completed:'مكتملة',failed:'فشلت',partially_completed:'مكتملة جزئيًا',cancelled:'ملغاة'} as Row)[v]||v
